// Import necessary classes from Spring Security package
import org.springframework.security.core.userdetails.User; // UserDetails interface, inherits it and provides more methods than just username & password details  	    	 	   		     			   	     					 – Principal -> getName() method for identifying user is used (Optional) by Spring Security
import org.springframework.security.core.userdetails.UserDetails; // interface, inherits it and contains all necessary methods of the User object to identify an authenticated principal with details like username/password etc...    	  	 	   		 – Authentication -> getAuthorities() method for identifying roles or authorities
import org.springframework.security.core.userdetails.UserDetailsService; // defines custom interface which extends 'loadUserByUsername' to provide user-specific data (username, password and authority)    	  	 	   		 – UserDetail service -> loadUsers(Optional), hashedPasswords method is used by Spring Security
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; // encodes the input using BCrypt algorithm (default cost parameter of bcrypt) and checks whether given password matches encoded one    – Authentication -> check(Credentials), BCrypt is used for security sensitive operations
import org.springframework.security.provisioning.InMemoryUserDetailsManager;	// defines a 'userdetails' service that stores users in memory (Optional, use if you want to store the user details somewhere else like database) – UserDetail manager -> createUser('username', passwordEncoder().encode(password), roles);
import org.springframework.security.config.annotation.web.configuration.*; // @Configuration for Spring's 'bean scan'. You can place it above method annotated with "@Bean"    --Spring Security Config-- – web -> configure (WebSecurityConfigurerAdapter) is used to override default security configuration
import org.springframework.security.config.annotation.web.*; // @EnableWebSecurity & others for Spring's 'bean scan'. You can place it above method annotated with "@Bean" --Spring Security Config-- – web -> configure (HttpSecurity) is used to restrict HTTP requests, specify access rules
import org.springframework.security.config.annotation.*; // @EnableGlobalMethodSecurity & others for Spring's 'bean scan'. You can place it above method annotated with "@Bean" --Spring Security Config-- – web -> configure (DaoAuthenticationConfigurerAdapter) is used to provide DAO authentication, user details service